import 'dart:io';

import 'package:fluttersdk_artisan/artisan.dart';
import 'package:example/app/commands/_index.g.dart' as consumer_commands;
import '../lib/app/_plugins.g.dart' as plugins;

/// Native Flutter consumer wrapper (canonical scaffold from
/// `consumer:scaffold`). Wires:
///
/// - consumer commands from `lib/app/commands/` via the codegen barrel
///   `lib/app/commands/_index.g.dart` (regenerated by every
///   `make:command` invocation in the consumer).
/// - plugin providers via `lib/app/_plugins.g.dart` (regenerated by
///   `plugin:install <name>` / `plugins:refresh` from the
///   `.artisan/plugins.json` registry).
///
/// New plugins surface automatically after `plugin:install <name>` AND
/// the parent app's pubspec.yaml lists the plugin under `dependencies:`.
/// No manual edit to this file is required.
class _ConsumerCommandsProvider extends ArtisanServiceProvider {
  @override
  List<ArtisanCommand> commands() => consumer_commands.commands;
}

Future<void> main(List<String> args) async {
  exit(
    await runArtisan(
      args,
      baseProviders: [
        _ConsumerCommandsProvider(),
        ...plugins.autoDiscoveredProviders(),
      ],
      delegateToConsumer: false,
    ),
  );
}
